+++ b/packages/ui/src/engine/pixel-characters.ts
@@ ... @@
+// Speech/thought bubble rendering and management
+const speechQuips = [
+  "By my sword!",
+  "For the king!",
+  "Hark, a tale!",
+  "Anon, anon!",
+  "Fie on this!",
+  "Zounds!",
+  "Methinks so.",
+  "Pray, attend!",
+  "Huzzah!",
+  "Well met!",
+];
+
+interface BubbleState {
+  text: string;
+  isThought: boolean;
+  startTime: number;
+}
+
+const bubbleStates = new Map<string, BubbleState>();
+
+/**
+ * Draw a pixel-art style speech or thought bubble with pointer.
+ * @param ctx CanvasRenderingContext2D
+ * @param x X coordinate (top-center of bubble pointer)
+ * @param y Y coordinate (top-center of bubble pointer)
+ * @param text Text to display inside bubble
+ * @param isThought If true, draw thought bubble style (dotted border)
+ */
+export function drawSpeechBubble(ctx: CanvasRenderingContext2D, x: number, y: number, text: string, isThought: boolean) {
+  const paddingX = 6;
+  const paddingY = 4;
+  const maxWidth = 200;
+  const lineHeight = 12;
+
+  // Clamp text length to 30 chars
+  if (text.length > 30) text = text.slice(0, 27) + "...";
+
+  // Split text into lines by max width estimation (approx 7px per char)
+  const approxCharWidth = 7;
+  const maxCharsPerLine = Math.floor((maxWidth - paddingX * 2) / approxCharWidth);
+  const words = text.split(" ");
+  const lines: string[] = [];
+  let currentLine = "";
+  for (const word of words) {
+    if ((currentLine + " " + word).trim().length <= maxCharsPerLine) {
+      currentLine = (currentLine + " " + word).trim();
+    } else {
+      if (currentLine) lines.push(currentLine);
+      currentLine = word;
+    }
+  }
+  if (currentLine) lines.push(currentLine);
+
+  const bubbleWidth = Math.min(maxWidth, Math.max(...lines.map(l => l.length)) * approxCharWidth + paddingX * 2);
+  const bubbleHeight = lines.length * lineHeight + paddingY * 2;
+
+  // Bubble rectangle top-left
+  const bx = x - bubbleWidth / 2;
+  const by = y - bubbleHeight - 12; // 12px pointer height
+
+  // Draw bubble shape with rounded rect and pointer
+  ctx.save();
+  ctx.lineWidth = 1;
+  ctx.strokeStyle = "#222222";
+  ctx.fillStyle = "#ffffff";
+
+  // Draw rounded rect
+  const radius = 6;
+  ctx.beginPath();
+  ctx.moveTo(bx + radius, by);
+  ctx.lineTo(bx + bubbleWidth - radius, by);
+  ctx.quadraticCurveTo(bx + bubbleWidth, by, bx + bubbleWidth, by + radius);
+  ctx.lineTo(bx + bubbleWidth, by + bubbleHeight - radius);
+  ctx.quadraticCurveTo(bx + bubbleWidth, by + bubbleHeight, bx + bubbleWidth - radius, by + bubbleHeight);
+
+  // Pointer triangle at bottom center
+  const pointerX = x;
+  const pointerY = y;
+  ctx.lineTo(pointerX + 8, by + bubbleHeight);
+  ctx.lineTo(pointerX, pointerY);
+  ctx.lineTo(pointerX - 8, by + bubbleHeight);
+
+  ctx.lineTo(bx + radius, by + bubbleHeight);
+  ctx.quadraticCurveTo(bx, by + bubbleHeight, bx, by + bubbleHeight - radius);
+  ctx.lineTo(bx, by + radius);
+  ctx.quadraticCurveTo(bx, by, bx + radius, by);
+  ctx.closePath();
+
+  if (isThought) {
+    // Thought bubble: white fill with dotted dark border
+    ctx.fill();
+    ctx.setLineDash([2, 3]);
+    ctx.stroke();
+    ctx.setLineDash([]);
+  } else {
+    // Speech bubble: white fill with solid dark border
+    ctx.fill();
+    ctx.stroke();
+  }
+
+  // Draw text lines
+  ctx.fillStyle = "#222222";
+  ctx.font = "10px monospace";
+  ctx.textBaseline = "top";
+  for (let i = 0; i < lines.length; i++) {
+    ctx.fillText(lines[i], bx + paddingX, by + paddingY + i * lineHeight);
+  }
+
+  ctx.restore();
+}
+
+/**
+ * Update or create bubble state for a character.
+ * @param id Character id
+ * @param text Text to show
+ * @param isThought Thought bubble flag
+ */
+export function setCharacterBubble(id: string, text: string, isThought: boolean) {
+  bubbleStates.set(id, { text, isThought, startTime: performance.now() });
+}
+
+/**
+ * Draw bubbles for all characters with active bubbles.
+ * Auto-hide bubbles after 3 seconds.
+ * @param ctx CanvasRenderingContext2D
+ * @param charPositions Map of character id to position {x,y}
+ */
+export function drawCharacterBubbles(ctx: CanvasRenderingContext2D, charPositions: Map<string, { x: number; y: number }>) {
+  const now = performance.now();
+  for (const [id, bubble] of bubbleStates.entries()) {
+    if (now - bubble.startTime > 3000) {
+      bubbleStates.delete(id);
+      continue;
+    }
+    const pos = charPositions.get(id);
+    if (!pos) continue;
+    drawSpeechBubble(ctx, pos.x, pos.y - 24, bubble.text, bubble.isThought);
+  }
+}
+
+/**
+ * Call this function per frame to update bubbles for characters.
+ * Characters working show current task title.
+ * Idle characters show random medieval quips.
+ * @param charStates Map of character id to CharState
+ * @param charTasks Map of character id to current task title string or null
+ */
+export function updateCharacterBubbles(charStates: Map<string, CharState>, charTasks: Map<string, string | null>) {
+  for (const [id, state] of charStates.entries()) {
+    const task = charTasks.get(id);
+    if (task) {
+      // Working: show task title in speech bubble
+      setCharacterBubble(id, task, false);
+    } else {
+      // Idle: show random quip as thought bubble
+      if (!bubbleStates.has(id)) {
+        const quip = speechQuips[Math.floor(Math.random() * speechQuips.length)];
+        setCharacterBubble(id, quip, true);
+      }
+    }
+  }
+}
+
